block2       -0.1000000    0.2    0.1 -2.220446e-17 -2.220446e-17 -2.220446e-17
block3       -0.1000000    0.1    0.2 -2.220446e-17 -2.220446e-17 -2.220446e-17
geng2        -0.1333333    0.0    0.0  2.666667e-01  1.333333e-01  1.333333e-01
geng3        -0.1333333    0.0    0.0  1.333333e-01  2.666667e-01  1.333333e-01
geng4        -0.1333333    0.0    0.0  1.333333e-01  1.333333e-01  2.666667e-01
